import{_ as a,c as i,o as s,ak as r,al as t}from"./chunks/framework.DHLlVITf.js";const p=JSON.parse('{"title":"AireAssert Release Notes","description":"","frontmatter":{},"headers":[],"relativePath":"aireblock-releases/aireassert-v1-3-1.md","filePath":"aireblock-releases/aireassert-v1-3-1.md","lastUpdated":1783593438000}'),l={name:"aireblock-releases/aireassert-v1-3-1.md"};function n(o,e,c,h,d,u){return s(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="aireassert-release-notes" tabindex="-1"><span class="fsc-product"><img src="'+t+'"> AireAssert Release Notes</span> <a class="header-anchor" href="#aireassert-release-notes" aria-label="Permalink to “AireAssert Release Notes”">​</a></h1><blockquote><p><strong>Version:</strong> 1.3.1<br><strong>Release Date:</strong> 26th May 2026</p></blockquote><h2 id="summary-of-changes" tabindex="-1">Summary of Changes <a class="header-anchor" href="#summary-of-changes" aria-label="Permalink to “Summary of Changes”">​</a></h2><h4 id="✨-new-features" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features" aria-label="Permalink to “✨ New Features”">​</a></h4><ul><li>Multi-Select Control Behaviour Verification (AA-938)</li></ul><h4 id="🐞-bug-fixes" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h4><ul><li>Enabled and Disabled Issues (AA-936)</li><li>Runner Crash with Multiple AireFrame Scenarios (AA-946)</li><li>PowerShell SDK Breaking Git Integration (AA-968)</li></ul><hr><h1 id="detailed-changes" tabindex="-1">Detailed Changes <a class="header-anchor" href="#detailed-changes" aria-label="Permalink to “Detailed Changes”">​</a></h1><h3 id="✨-new-features-1" tabindex="-1">✨ New Features <a class="header-anchor" href="#✨-new-features-1" aria-label="Permalink to “✨ New Features”">​</a></h3><hr><h4 id="multi-select-control-behaviour-verification-aa-938" tabindex="-1">Multi-Select Control Behaviour Verification (AA-938) <a class="header-anchor" href="#multi-select-control-behaviour-verification-aa-938" aria-label="Permalink to “Multi-Select Control Behaviour Verification (AA-938)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Verified and resolved the behaviour of multi-select controls within AireAssert scenarios, issue was due to in-flight requests blocking form submission, which can now be awaited and handled.</p></div><div class="tip custom-block"><p class="custom-block-title">What this means for you</p><p>Use of the command</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>And we wait up to 60 seconds for any in-flight requests to complete</span></span></code></pre></div><p>allows potential waits to be accounted for.</p></div><h3 id="🐞-bug-fixes-1" tabindex="-1">🐞 Bug Fixes <a class="header-anchor" href="#🐞-bug-fixes-1" aria-label="Permalink to “🐞 Bug Fixes”">​</a></h3><hr><h4 id="enabled-and-disabled-issues-aa-936" tabindex="-1">Enabled and Disabled Issues (AA-936) <a class="header-anchor" href="#enabled-and-disabled-issues-aa-936" aria-label="Permalink to “Enabled and Disabled Issues (AA-936)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed an issue with the handling of enabled and disabled states within AireAssert. Controls that were incorrectly enabled or disabled during test execution will now behave as expected.</p></div><h4 id="runner-crash-with-multiple-aireframe-scenarios-aa-946" tabindex="-1">Runner Crash with Multiple AireFrame Scenarios (AA-946) <a class="header-anchor" href="#runner-crash-with-multiple-aireframe-scenarios-aa-946" aria-label="Permalink to “Runner Crash with Multiple AireFrame Scenarios (AA-946)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Fixed a crash in the AireAssert runner that occurred when multiple AireFrame scenarios were included in the same feature file. Previously, the second scenario would hang indefinitely on the step that loads AireFrame; this has now been resolved so all scenarios run to completion correctly.</p></div><h4 id="powershell-sdk-breaking-git-integration-aa-968" tabindex="-1">PowerShell SDK Breaking Git Integration (AA-968) <a class="header-anchor" href="#powershell-sdk-breaking-git-integration-aa-968" aria-label="Permalink to “PowerShell SDK Breaking Git Integration (AA-968)”">​</a></h4><div class="info custom-block"><p class="custom-block-title">Description</p><p>Resolved an issue where an upgraded PowerShell SDK was breaking git integration within AireAssert. Git operations will now function correctly and we will try an upgrade to a future version as it becomes available.</p></div>',22)])])}const m=a(l,[["render",n]]);export{p as __pageData,m as default};
